-- Function: safely book a property date range
-- Returns booking_id on success, NULL on conflict
CREATE OR REPLACE FUNCTION book_property(
  p_property_id UUID,
  p_guest_id UUID,
  p_check_in DATE,
  p_check_out DATE,
  p_price NUMERIC
) RETURNS UUID AS $$
DECLARE
  v_booking_id UUID;
  v_version INT;
  v_locked BOOLEAN := FALSE;
  v_retries INT := 0;
BEGIN
  LOOP
    BEGIN
      -- Use SERIALIZABLE isolation for critical booking path
      SET TRANSACTION ISOLATION LEVEL SERIALIZABLE;

      -- Lock the specific date rows for this property
      -- Prevents phantom reads: no other transaction can insert
      -- overlapping bookings for these dates simultaneously
      SELECT version INTO v_version
      FROM property_availability
      WHERE property_id = p_property_id
        AND date >= p_check_in
        AND date < p_check_out
      FOR UPDATE;

      -- Re-verify availability inside the lock
      -- The earlier cache/read-replica check was speculative;
      -- this is the authoritative check
      IF EXISTS (
        SELECT 1 FROM bookings
        WHERE property_id = p_property_id
          AND status = 'confirmed'
          AND daterange(p_check_in, p_check_out, '[)')
          && daterange(check_in, check_out, '[)')
        FOR UPDATE
      ) THEN
        ROLLBACK;
        RETURN NULL;  -- Already booked
      END IF;

      -- Insert the booking with optimistic lock check
      INSERT INTO bookings (
        property_id, guest_id, check_in, check_out,
        price, status, version
      ) VALUES (
        p_property_id, p_guest_id, p_check_in, p_check_out,
        p_price, 'confirmed', v_version + 1
      )
      RETURNING id INTO v_booking_id;

      -- Update availability version
      UPDATE property_availability
      SET version = version + 1, is_available = FALSE
      WHERE property_id = p_property_id
        AND date >= p_check_in
        AND date < p_check_out;

      COMMIT;
      RETURN v_booking_id;

    EXCEPTION
      WHEN SERIALIZATION_FAILURE THEN
        -- Retry with exponential backoff
        ROLLBACK;
        v_retries := v_retries + 1;
        IF v_retries >= 3 THEN
          RETURN NULL;
        END IF;
        PERFORM pg_sleep(power(2, v_retries) * 0.1);
      WHEN OTHERS THEN
        ROLLBACK;
        RAISE;
    END;
  END LOOP;
END;
$$ LANGUAGE plpgsql;
